package com.example.search.service;

import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.support.master.AcknowledgedResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.CreateIndexResponse;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

@Service
public class IndexManagementService {

    public static final String PRODUCTS_INDEX = "products";
    public static final String QUERIES_INDEX = "search_queries";

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    @Value("${elasticsearch.products.shards:1}")
    private int productsShards;

    @Value("${elasticsearch.products.replicas:0}")
    private int productsReplicas;

    public IndexManagementService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    public void ensureIndices() throws IOException {
        ensureProductsIndex();
        ensureQueriesIndex();
    }

    public void recreateAll() throws IOException {
        deleteIfExists(PRODUCTS_INDEX);
        deleteIfExists(QUERIES_INDEX);
        ensureIndices();
    }

    private void deleteIfExists(String index) throws IOException {
        if (client.indices().exists(new GetIndexRequest(index), RequestOptions.DEFAULT)) {
            AcknowledgedResponse resp = client.indices().delete(new DeleteIndexRequest(index), RequestOptions.DEFAULT);
            if (!resp.isAcknowledged()) throw new IOException("Delete index not acknowledged: " + index);
        }
    }

    private void ensureProductsIndex() throws IOException {
        if (client.indices().exists(new GetIndexRequest(PRODUCTS_INDEX), RequestOptions.DEFAULT)) return;

        Map<String, Object> mapping = new HashMap<>();
        Map<String, Object> properties = new HashMap<>();

        properties.put("sku", field("keyword"));
        properties.put("name", textWithKeyword());
        properties.put("description", field("text"));
        properties.put("brand", keywordWithText());
        properties.put("categories", keywordWithText());
        properties.put("price", field("scaled_float", "scaling_factor", 100));
        properties.put("currency", field("keyword"));
        properties.put("inStock", field("boolean"));
        properties.put("rating", field("half_float"));
        properties.put("reviewCount", field("integer"));
        properties.put("createdAt", field("date"));
        properties.put("updatedAt", field("date"));

        Map<String, Object> attributes = new HashMap<>();
        attributes.put("type", "flattened");
        properties.put("attributes", attributes);

        mapping.put("properties", properties);

        CreateIndexRequest req = new CreateIndexRequest(PRODUCTS_INDEX);
        req.settings(Settings.builder()
                .put("index.number_of_shards", productsShards)
                .put("index.number_of_replicas", productsReplicas)
                .put("analysis.analyzer.folded.type", "custom")
                .putList("analysis.analyzer.folded.filter", "lowercase", "asciifolding")
                .put("analysis.analyzer.folded.tokenizer", "standard")
        );

        req.source(objectMapper.writeValueAsString(mapping), XContentType.JSON);

        CreateIndexResponse resp = client.indices().create(req, RequestOptions.DEFAULT);
        if (!resp.isAcknowledged()) throw new IOException("Create index not acknowledged: " + PRODUCTS_INDEX);
    }

    private void ensureQueriesIndex() throws IOException {
        if (client.indices().exists(new GetIndexRequest(QUERIES_INDEX), RequestOptions.DEFAULT)) return;

        Map<String, Object> mapping = new HashMap<>();
        Map<String, Object> properties = new HashMap<>();
        properties.put("query", field("text"));
        properties.put("timestamp", field("date"));
        properties.put("customerId", field("keyword"));
        properties.put("sessionId", field("keyword"));
        properties.put("filters", field("flattened"));
        properties.put("from", field("integer"));
        properties.put("size", field("integer"));
        properties.put("totalHits", field("long"));
        properties.put("tookMs", field("long"));
        mapping.put("properties", properties);

        CreateIndexRequest req = new CreateIndexRequest(QUERIES_INDEX);
        req.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0)
        );
        req.source(objectMapper.writeValueAsString(mapping), XContentType.JSON);

        CreateIndexResponse resp = client.indices().create(req, RequestOptions.DEFAULT);
        if (!resp.isAcknowledged()) throw new IOException("Create index not acknowledged: " + QUERIES_INDEX);
    }

    private Map<String, Object> field(String type) {
        Map<String, Object> m = new HashMap<>();
        m.put("type", type);
        return m;
    }

    private Map<String, Object> field(String type, String k, Object v) {
        Map<String, Object> m = new HashMap<>();
        m.put("type", type);
        m.put(k, v);
        return m;
    }

    private Map<String, Object> textWithKeyword() {
        Map<String, Object> m = new HashMap<>();
        m.put("type", "text");
        m.put("analyzer", "folded");
        Map<String, Object> fields = new HashMap<>();
        fields.put("keyword", field("keyword"));
        m.put("fields", fields);
        return m;
    }

    private Map<String, Object> keywordWithText() {
        Map<String, Object> m = new HashMap<>();
        m.put("type", "keyword");
        Map<String, Object> fields = new HashMap<>();
        Map<String, Object> t = new HashMap<>();
        t.put("type", "text");
        t.put("analyzer", "folded");
        fields.put("text", t);
        m.put("fields", fields);
        return m;
    }
}

package com.example.search.service;

import com.example.search.dto.ProductIndexRequest;
import com.example.search.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.DocWriteRequest;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.List;
import java.util.UUID;

import static com.example.search.service.IndexManagementService.PRODUCTS_INDEX;

@Service
public class ProductIndexService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductIndexService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    public String index(ProductIndexRequest req) throws IOException {
        String id = (req.getId() == null || req.getId().isBlank()) ? UUID.randomUUID().toString() : req.getId();

        Product p = new Product();
        p.setId(id);
        p.setSku(req.getSku());
        p.setName(req.getName());
        p.setDescription(req.getDescription());
        p.setBrand(req.getBrand());
        p.setCategories(req.getCategories());
        p.setPrice(req.getPrice());
        p.setCurrency(req.getCurrency());
        p.setInStock(req.getInStock() != null && req.getInStock());
        p.setRating(req.getRating() == null ? 0.0 : req.getRating());
        p.setReviewCount(req.getReviewCount() == null ? 0 : req.getReviewCount());
        p.setAttributes(req.getAttributes());
        Instant now = Instant.now();
        p.setCreatedAt(now);
        p.setUpdatedAt(now);

        IndexRequest ir = new IndexRequest(PRODUCTS_INDEX)
                .id(id)
                .source(objectMapper.writeValueAsString(p), XContentType.JSON)
                .opType(DocWriteRequest.OpType.INDEX);

        client.index(ir, RequestOptions.DEFAULT);
        return id;
    }

    public void upsert(ProductIndexRequest req) throws IOException {
        String id = req.getId();
        if (id == null || id.isBlank()) throw new IllegalArgumentException("id is required for upsert");

        Instant now = Instant.now();

        UpdateRequest ur = new UpdateRequest(PRODUCTS_INDEX, id);
        ur.doc(objectMapper.writeValueAsString(new PartialUpdate(now, req)), XContentType.JSON);
        ur.docAsUpsert(true);

        client.update(ur, RequestOptions.DEFAULT);
    }

    public BulkResponse bulkUpsert(List<ProductIndexRequest> requests) throws IOException {
        BulkRequest br = new BulkRequest();
        Instant now = Instant.now();
        for (ProductIndexRequest req : requests) {
            String id = req.getId();
            if (id == null || id.isBlank()) id = UUID.randomUUID().toString();
            UpdateRequest ur = new UpdateRequest(PRODUCTS_INDEX, id);
            ur.doc(objectMapper.writeValueAsString(new PartialUpdate(now, req)), XContentType.JSON);
            ur.docAsUpsert(true);
            br.add(ur);
        }
        return client.bulk(br, RequestOptions.DEFAULT);
    }

    private static class PartialUpdate {
        public String sku;
        public String name;
        public String description;
        public String brand;
        public List<String> categories;
        public Object price;
        public String currency;
        public Boolean inStock;
        public Double rating;
        public Integer reviewCount;
        public Object attributes;
        public Instant updatedAt;
        public Instant createdAt;

        PartialUpdate(Instant now, ProductIndexRequest req) {
            this.sku = req.getSku();
            this.name = req.getName();
            this.description = req.getDescription();
            this.brand = req.getBrand();
            this.categories = req.getCategories();
            this.price = req.getPrice();
            this.currency = req.getCurrency();
            this.inStock = req.getInStock();
            this.rating = req.getRating();
            this.reviewCount = req.getReviewCount();
            this.attributes = req.getAttributes();
            this.updatedAt = now;
            this.createdAt = now;
        }
    }
}

package com.example.search.service;

import com.example.search.dto.ProductSearchRequest;
import com.example.search.dto.ProductSearchResponse;
import com.example.search.model.Product;
import com.example.search.model.SearchQueryLog;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.unit.Fuzziness;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;

import static com.example.search.service.IndexManagementService.PRODUCTS_INDEX;
import static com.example.search.service.IndexManagementService.QUERIES_INDEX;

@Service
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductSearchService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    public ProductSearchResponse search(ProductSearchRequest req) throws IOException {
        long startNs = System.nanoTime();

        SearchRequest sr = new SearchRequest(PRODUCTS_INDEX);
        SearchSourceBuilder ssb = new SearchSourceBuilder();

        BoolQueryBuilder bq = QueryBuilders.boolQuery();

        if (req.getQuery() != null && !req.getQuery().isBlank()) {
            MultiMatchQueryBuilder mm = QueryBuilders.multiMatchQuery(req.getQuery(), "name", "description", "brand.text", "categories.text")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness(Fuzziness.AUTO)
                    .prefixLength(1)
                    .operator(org.elasticsearch.index.query.Operator.AND);
            bq.must(mm);
        } else {
            bq.must(QueryBuilders.matchAllQuery());
        }

        if (req.getCategories() != null && !req.getCategories().isEmpty()) {
            bq.filter(QueryBuilders.termsQuery("categories", req.getCategories()));
        }
        if (req.getBrands() != null && !req.getBrands().isEmpty()) {
            bq.filter(QueryBuilders.termsQuery("brand", req.getBrands()));
        }
        if (req.getInStock() != null) {
            bq.filter(QueryBuilders.termQuery("inStock", req.getInStock()));
        }
        if (req.getMinPrice() != null || req.getMaxPrice() != null) {
            var r = QueryBuilders.rangeQuery("price");
            if (req.getMinPrice() != null) r.gte(req.getMinPrice());
            if (req.getMaxPrice() != null) r.lte(req.getMaxPrice());
            bq.filter(r);
        }
        if (req.getAttributeFilters() != null && !req.getAttributeFilters().isEmpty()) {
            for (Map.Entry<String, List<String>> e : req.getAttributeFilters().entrySet()) {
                if (e.getKey() == null || e.getKey().isBlank()) continue;
                if (e.getValue() == null || e.getValue().isEmpty()) continue;
                String field = "attributes." + e.getKey();
                bq.filter(QueryBuilders.termsQuery(field, e.getValue()));
            }
        }

        ssb.query(bq);
        ssb.from(req.getFrom() == null ? 0 : req.getFrom());
        ssb.size(req.getSize() == null ? 20 : req.getSize());

        ssb.sort("_score", SortOrder.DESC);
        ssb.sort("rating", SortOrder.DESC);
        ssb.sort("reviewCount", SortOrder.DESC);

        ssb.aggregation(AggregationBuilders.terms("facet_brand").field("brand").size(50));
        ssb.aggregation(AggregationBuilders.terms("facet_categories").field("categories").size(50));
        ssb.aggregation(AggregationBuilders.terms("facet_inStock").field("inStock").size(2));

        sr.source(ssb);

        SearchResponse resp = client.search(sr, RequestOptions.DEFAULT);

        List<Product> products = new ArrayList<>();
        for (SearchHit hit : resp.getHits().getHits()) {
            Map<String, Object> src = hit.getSourceAsMap();
            Product p = objectMapper.convertValue(src, Product.class);
            if (p.getId() == null) p.setId(hit.getId());
            products.add(p);
        }

        Map<String, List<ProductSearchResponse.FacetBucket>> facets = new LinkedHashMap<>();
        facets.put("brand", toBuckets((Terms) resp.getAggregations().get("facet_brand")));
        facets.put("categories", toBuckets((Terms) resp.getAggregations().get("facet_categories")));
        facets.put("inStock", toBuckets((Terms) resp.getAggregations().get("facet_inStock")));

        long total = resp.getHits().getTotalHits() == null ? products.size() : resp.getHits().getTotalHits().value;
        long tookMs = resp.getTook().getMillis();

        ProductSearchResponse out = new ProductSearchResponse();
        out.setProducts(products);
        out.setFacets(facets);
        out.setTotal(total);
        out.setFrom(ssb.from());
        out.setSize(ssb.size());
        out.setTookMs(tookMs);

        long endNs = System.nanoTime();
        indexQueryLog(req, total, tookMs, (endNs - startNs) / 1_000_000);

        return out;
    }

    private List<ProductSearchResponse.FacetBucket> toBuckets(Terms terms) {
        List<ProductSearchResponse.FacetBucket> list = new ArrayList<>();
        if (terms == null) return list;
        for (Terms.Bucket b : terms.getBuckets()) {
            list.add(new ProductSearchResponse.FacetBucket(String.valueOf(b.getKey()), b.getDocCount()));
        }
        return list;
    }

    private void indexQueryLog(ProductSearchRequest req, long totalHits, long esTookMs, long totalTookMs) {
        try {
            SearchQueryLog log = new SearchQueryLog();
            log.setId(UUID.randomUUID().toString());
            log.setQuery(req.getQuery());
            log.setTimestamp(Instant.now());
            log.setCustomerId(req.getCustomerId());
            log.setSessionId(req.getSessionId());

            Map<String, Object> filters = new LinkedHashMap<>();
            if (req.getCategories() != null) filters.put("categories", req.getCategories());
            if (req.getBrands() != null) filters.put("brands", req.getBrands());
            if (req.getInStock() != null) filters.put("inStock", req.getInStock());
            if (req.getMinPrice() != null) filters.put("minPrice", req.getMinPrice());
            if (req.getMaxPrice() != null) filters.put("maxPrice", req.getMaxPrice());
            if (req.getAttributeFilters() != null) filters.put("attributes", req.getAttributeFilters());
            log.setFilters(filters);

            log.setFrom(req.getFrom());
            log.setSize(req.getSize());
            log.setTotalHits(totalHits);
            log.setTookMs(esTookMs);

            IndexRequest ir = new IndexRequest(QUERIES_INDEX)
                    .id(log.getId())
                    .source(objectMapper.writeValueAsString(log), XContentType.JSON);
            client.index(ir, RequestOptions.DEFAULT);
        } catch (Exception ignored) {
        }
    }
}

package com.example.search.controller;

import com.example.search.dto.ProductIndexRequest;
import com.example.search.dto.ProductSearchRequest;
import com.example.search.dto.ProductSearchResponse;
import com.example.search.service.IndexManagementService;
import com.example.search.service.ProductIndexService;
import com.example.search.service.ProductSearchService;
import org.elasticsearch.action.bulk.BulkResponse;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class ProductSearchController {

    private final IndexManagementService indexManagementService;
    private final ProductIndexService productIndexService;
    private final ProductSearchService productSearchService;

    public ProductSearchController(IndexManagementService indexManagementService,
                                   ProductIndexService productIndexService,
                                   ProductSearchService productSearchService) {
        this.indexManagementService = indexManagementService;
        this.productIndexService = productIndexService;
        this.productSearchService = productSearchService;
    }

    @PostMapping("/admin/indices/ensure")
    public ResponseEntity<Map<String, Object>> ensure() throws IOException {
        indexManagementService.ensureIndices();
        return ResponseEntity.ok(Map.of("status", "ok"));
    }

    @PostMapping("/admin/indices/recreate")
    public ResponseEntity<Map<String, Object>> recreate() throws IOException {
        indexManagementService.recreateAll();
        return ResponseEntity.ok(Map.of("status", "ok"));
    }

    @PostMapping("/products")
    public ResponseEntity<Map<String, Object>> index(@RequestBody ProductIndexRequest req) throws IOException {
        String id = productIndexService.index(req);
        return ResponseEntity.ok(Map.of("id", id));
    }

    @PutMapping("/products/{id}")
    public ResponseEntity<Map<String, Object>> upsert(@PathVariable String id, @RequestBody ProductIndexRequest req) throws IOException {
        req.setId(id);
        productIndexService.upsert(req);
        return ResponseEntity.ok(Map.of("status", "ok"));
    }

    @PostMapping("/products/_bulkUpsert")
    public ResponseEntity<Map<String, Object>> bulkUpsert(@RequestBody List<ProductIndexRequest> reqs) throws IOException {
        BulkResponse resp = productIndexService.bulkUpsert(reqs);
        return ResponseEntity.ok(Map.of(
                "took", resp.getTook().getMillis(),
                "hasFailures", resp.hasFailures(),
                "failureMessage", resp.hasFailures() ? resp.buildFailureMessage() : null
        ));
    }

    @PostMapping("/search")
    public ResponseEntity<ProductSearchResponse> search(@RequestBody ProductSearchRequest req) throws IOException {
        return ResponseEntity.ok(productSearchService.search(req));
    }
}

package com.example.search.config;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.SerializationFeature;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class JacksonConfig {
    @Bean
    public ObjectMapper objectMapper() {
        ObjectMapper om = new ObjectMapper();
        om.registerModule(new JavaTimeModule());
        om.disable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS);
        return om;
    }
}

package com.example.search;

import com.example.search.service.IndexManagementService;
import org.springframework.boot.ApplicationRunner;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class Startup {

    @Bean
    public ApplicationRunner ensureIndicesAtStartup(IndexManagementService indexManagementService) {
        return args -> indexManagementService.ensureIndices();
    }
}

package com.example.search.error;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<Map<String, Object>> illegalArgument(IllegalArgumentException e) {
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(Map.of("error", e.getMessage()));
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<Map<String, Object>> generic(Exception e) {
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(Map.of("error", "internal_error", "message", e.getMessage()));
    }
}

